export default function handler(req, res) {
  // CORS
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  
  if (req.method === 'OPTIONS') {
    return res.status(200).end();
  }
  
  if (req.method === 'GET') {
    // Serve agent card for discovery
    return res.json(agentCard);
  }
  
  if (req.method === 'POST') {
    const { jsonrpc, method, params, id } = req.body || {};
    
    // JSON-RPC routing
    if (method === 'rpc.discover' || method === 'agent/card') {
      return res.json({ jsonrpc: '2.0', id, result: agentCard });
    }
    
    if (method === 'faq.search') {
      const query = (params?.query || '').toLowerCase();
      const matches = faqs.filter(f => 
        f.q.toLowerCase().includes(query) || f.a.toLowerCase().includes(query)
      );
      return res.json({ jsonrpc: '2.0', id, result: { faqs: matches } });
    }
    
    // Default: return skills list
    return res.json({
      jsonrpc: '2.0',
      id,
      result: {
        agent: agentCard.name,
        description: agentCard.description,
        skills: agentCard.skills.map(s => ({ id: s.id, name: s.name, description: s.description })),
        faqs: faqs.length
      }
    });
  }
  
  return res.status(405).json({ error: 'Method not allowed' });
}
